2138→  private buildTooltipText(dot: DotElement): string {
2139→    let fullText = (dot.getAttribute('aria-label') || '').trim();
2140→    const id = dot.dataset.targetTurnId || '';
2141→    if (id && this.starred.has(id)) fullText = `★ ${fullText}`;
2142→
2143→    if (this.showMessageTimestampsEnabled && id && this.timestampService) {
2144→      const ts = this.timestampService.getTimestamp(id as TurnId);
2145→      if (typeof ts === 'number') {
2146→        fullText = `${this.timestampService.formatAbsoluteTime(ts)}\n${fullText}`;
2147→      }
2148→    }
2149→    return fullText;

