371→  private computeElementTopsInScrollContainer(elements: HTMLElement[]): number[] {
372→    if (!this.scrollContainer || elements.length === 0) return [];
373→
374→    const containerRect = this.scrollContainer.getBoundingClientRect();
375→    const scrollTop = this.scrollContainer.scrollTop;
376→
377→    const first = elements[0];
378→    const firstOffsetParent = first.offsetParent;
379→    const firstOffsetTop = first.offsetTop;
380→    const firstTop = first.getBoundingClientRect().top - containerRect.top + scrollTop;
381→
382→    const sameOffsetParent =
383→      firstOffsetParent !== null && elements.every((el) => el.offsetParent === firstOffsetParent);
384→
385→    const tops = elements.map((el) => {
386→      if (sameOffsetParent) {
387→        return firstTop + (el.offsetTop - firstOffsetTop);
388→      }
389→      return el.getBoundingClientRect().top - containerRect.top + scrollTop;
390→    });
391→
392→    for (let i = 1; i < tops.length; i++) {
393→      if (tops[i] < tops[i - 1]) return [];
394→    }
395→
396→    return tops;
397→  }
