415→  private isInResizeEdge(ev: PointerEvent): boolean {
416→    if (!this.ui.timelineBar) return false;
417→    const rect = this.ui.timelineBar.getBoundingClientRect();
418→    const barCenter = rect.left + rect.width / 2;
419→    const halfWidth = this.barWidth / 2;
420→    const ZONE = 6;
421→
422→    const leftEdge = barCenter - halfWidth;
423→    const rightEdge = barCenter + halfWidth;
424→    const nearLeft = ev.clientX >= leftEdge - 2 && ev.clientX <= leftEdge + ZONE;
425→    const nearRight = ev.clientX >= rightEdge - ZONE && ev.clientX <= rightEdge + 2;
426→    return nearLeft || nearRight;
