429→  private startResize(ev: PointerEvent): void {
430→    this.resizing = true;
431→    this.ui.timelineBar!.classList.add('timeline-resizing');
432→    this.ui.timelineBar!.setPointerCapture(ev.pointerId);
433→    const barRect = this.ui.timelineBar!.getBoundingClientRect();
434→    const barCenterX = barRect.left + barRect.width / 2;
435→
436→    this.onResizeMove = (e: PointerEvent) => {
437→      // Width = 2 × distance from pointer to bar center (symmetric expansion)
438→      const dist = Math.abs(e.clientX - barCenterX);
439→      this.barWidth = Math.max(this.barWidthMin, Math.min(this.barWidthMax, dist * 2));
440→      this.applyContainerVisibility();
441→    };
442→
443→    this.onResizeUp = (_e: PointerEvent) => {
444→      this.resizing = false;
445→      this.ui.timelineBar?.classList.remove('timeline-resizing');
446→      window.removeEventListener('pointermove', this.onResizeMove!);
447→      window.removeEventListener('pointerup', this.onResizeUp!);
448→      this.onResizeMove = null;
449→      this.onResizeUp = null;
450→      this.saveBarWidth();
451→    };
452→
453→    window.addEventListener('pointermove', this.onResizeMove);
454→    window.addEventListener('pointerup', this.onResizeUp, { once: true });
